/**통합 게시판코멘트 리스트*/
SELECT A.* FROM (

	SELECT A.*
	FROM t_board_comment A
	WHERE B_IDX=#{bIdx}
	ORDER BY G_IDX

) A

mapper.update:
/** 통합게시판코멘트 수정 */
UPDATE t_board_comment 
SET
	CONTENT=#{content}
	,MOD_DTIME=#{modDtime}
WHERE
	IDX=#{idx}

/** 통합게시판 답글관련 정보 수정 */
UPDATE t_board_comment 
SET	
	G_IDX=#{gIdx},
	G_ORD=#{gOrd},
	G_LVL=#{gLvl}
WHERE
	IDX=#{idx}
